def phosphor_icon(name: str, *, size: int = 18, color: str = "currentColor", weight: str = "fill") -> str:
    path = ICON_PATHS[name]
    return (
        f'<svg class="ph-icon" viewBox="0 0 256 256" width="{size}" height="{size}" '
        f'fill="{color}" data-weight="{weight}" aria-hidden="true" focusable="false">'
        f"<path d=\"{path}\"></path></svg>"
    )
